  # Render each triple in the original order and combine into one sentence
      clauses = []
      for t in triples:
          render = phrase_map.get(t.predicate)
          if render:
              clauses.append(render(t.subject, t.object))
          else:
              clauses.append(f"{t.subject} {t.predicate} {t.object}")

      if not clauses:
          return ""

      if len(clauses) == 1:
          final = clauses[0]
      else:
          final = ", ".join(clauses[:-1]) + ", and " + clauses[-1]

      return final.rstrip() + "."
